from machine import Pin, ADC
import network
import time
from umqtt.simple import MQTTClient

# WiFi configuration
ssid = 'your_wifi_ssid'
password = 'your_wifi_password'

# MQTT configuration
client_id = 'esp32_sensor'
broker_ip = 'broker_ip_address'
topic = 'sensors/temp'

# Connect to WiFi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(ssid, password)
    while not wlan.isconnected():
        pass
    print('Connected to WiFi')

# Read temperature from sensor (dummy function for illustration)
def read_temperature():
    adc = ADC(Pin(34))
    adc.atten(ADC.ATTN_11DB)
    return adc.read() * (3.3 / 4095) * 100  # Example conversion

# Connect to MQTT broker and publish data
def publish_sensor_data():
    client = MQTTClient(client_id, broker_ip)
    client.connect()
    try:
        while True:
            temp = read_temperature()
            client.publish(topic, str(temp))
            print(f'Published: {temp} to {topic}')
            time.sleep(10)
    finally:
        client.disconnect()

# Main function
def main():
    connect_wifi()
    publish_sensor_data()

